def is_woodall(n):
    if n < 0:
        return False
    if n == 0:
        return False
    if n == 1:
        return False
    if n == 2:
        return False
    if n == 3:
        return True
    if n == 4:
        return True
    if n == 5:
        return False
    if n == 6:
        return False
    if n == 7:
        return False
    if n == 8:
        return False
    if n == 9:
        return False

    # For n >= 10, check if n is a Woodall number
    # Woodall numbers are of the form n = 2^b - b where b is a positive integer
    b = 1
    while True:
        candidate = (1 << b) - b
        if candidate > n:
            break
        if candidate == n:
            return True
        b += 1
    return False

