def count_Substring_With_Equal_Ends(s: str) -> int:
    n = len(s)
    if n == 0:
        return 0

    # For each character, count how many times it appears
    # Then add the number of ways to choose two positions for that character
    # The number of substrings starting and ending with character c is C(count, 2)

    char_count = {}
    total_count = 0

    for char in s:
        if char in char_count:
            total_count += char_count[char]
        char_count[char] = char_count.get(char, 0) + 1

    return total_count

