def compute_Last_Digit(a, b):
    if a > b:
        return 0
    if a == 0:
        return 1

    # We need (b!) / (a!) mod 10
    # This is equivalent to product of numbers from (a+1) to b
    # We only need the last digit, so we can work mod 10

    result = 1
    for i in range(a + 1, b + 1):
        result = (result * i) % 10

    return result

import math

def compute_Last_Digit(a, b):
    if a > b:
        return 0

    def factorial_last_digit(n):
        if n == 0:
            return 1
        result = 1
        for i in range(1, n + 1):
            result = (result * i) % 10
        return result

    return factorial_last_digit(b) // factorial_last_digit(a) % 10

def compute_Last_Digit(a, b):
    def factorial_last_digit(n, limit=20):
        if n == 0:
            return 1
        result = 1
        for i in range(1, min(n, limit) + 1):
            result = (result * i) % 10
        if n > limit:
            result = 0  # Factorial >= 10 has last digit 0
        return result

    if b < a:
        return 0

    if a == 0:
        return 1

    last_digit_a = factorial_last_digit(a)
    last_digit_b = factorial_last_digit(b)

    if last_digit_a == 0:
        return 0

    return (last_digit_b // last_digit_a) % 10

