def find_Max_Num(digits, count):
    if count <= 0:
        return 0
    if len(digits) < count:
        return 0

    # Sort digits in descending order
    digits.sort(reverse=True)

    # If we need to form a number with fewer digits than available,
    # we take the largest 'count' digits
    result_digits = digits[:count]

    # Convert to integer
    return int("".join(map(str, result_digits)))

# Helper function (though not strictly needed for this logic)
def helper(digits, count):
    if not digits:
        return 0
    if count <= 0:
        return 0
    # This helper is just to ensure we can sort and slice as needed
    sorted_digits = sorted(digits, reverse=True)
    return sorted_digits[:count]

