def is_octagonal(n):
    if n <= 0:
        return False
    discriminant = 8 * n + 1
    if discriminant < 0:
        return False
    if discriminant % 7 != 0:
        return False
    root = int((discriminant // 7) ** 0.5)
    if root * root == discriminant // 7:
        if (root + 1) % 2 == 0:
            return True
    return False

