def is_octagonal(n):
    if n <= 0:
        return False
    discriminant = 1 + 8 * n
    sqrt_disc = int(discriminant ** 0.5)
    if sqrt_disc * sqrt_disc != discriminant:
        return False
    numerator = (sqrt_disc - 1) // 2
    if numerator <= 0:
        return False
    return numerator == (sqrt_disc - 1) // 2

def is_octagonal(n):
