        return False
    discriminant = 1 + 8 * n
    if discriminant < 0:
        return False
    sqrt_disc = discriminant ** 0.5
    if sqrt_disc != int(sqrt_disc):
        return False
    k = (1 + int(sqrt_disc)) / 2
    if k % 1 != 0:
        return False
    return True

def is_octagonal(n):
    if n <= 0:
        return False
    if n == 1:
        return True
    numerator = 1 + 6 * n
    discriminant = numerator + 48 * n
    if discriminant < 0:
        return False
    sqrt_discriminant = discriminant ** 0.5
    if sqrt_discriminant != int(sqrt_discriminant):
        return False
    numerator_sqrt = int(sqrt_discriminant)
    denominator = 3
    result = (numerator + numerator_sqrt) / denominator
    if result != int(result):
        return False
    return True

