def max_len_sub(arr, max_diff):
    """
    Find the maximum length of a subsequence where the difference between 
    adjacent elements is at most max_diff.

    Args:
        arr: List of integers
        max_diff: Maximum allowed difference between adjacent elements

    Returns:
        Maximum length of such a subsequence
    """
    if not arr:
        return 0

    n = len(arr)
    dp = [1] * n

    for i in range(n):
        for j in range(i):
            if abs(arr[i] - arr[j]) <= max_diff:
                dp[i] = max(dp[i], dp[j] + 1)

    return max(dp)

def max_len_sub(arr, diff):
    if not arr:
        return 0

    dp = {arr[0]: 1}

    for i in range(1, len(arr)):
        current = arr[i]
        target = current - diff
        if target in dp:
            dp[current] = max(dp.get(current, 0), dp[target] + 1)

    return max(dp.values()) if dp else 0

