from functools import lru_cache

@lru_cache(maxsize=None)
def bell_number(n):
    if n == 0:
        return 1

    bell = [0] * (n + 1)
    bell[0] = 1

    for i in range(1, n + 1):
        for j in range(i):
            bell[i] += bell[j] * bell_number(i - 1 - j)

    return bell[n]

# Test
assert bell_number(2) == 2

def bell_number(n):
    if n == 0:
        return 1
    if n == 1:
        return 1

    B = [[0] * (n + 1) for _ in range(n + 1)]
    B[0][0] = 1

    for i in range(1, n + 1):
        for j in range(0, i):
            B[i][j + 1] = B[i][j + 1] + B[i - 1][j]

    return B[n][n]

assert bell_number(2) == 2

