def eulerian_num(n, m):
    if m < 0 or m > n:
        return 0
    if n == 0:
        return 1 if m == 0 else 0

    # Use dynamic programming
    # A table where dp[i][j] is the number of permutations of length i with j ascents
    dp = [[0] * (n + 1) for _ in range(n + 1)]
    dp[0][0] = 1

    for i in range(1, n + 1):
        for j in range(i):
            dp[i][j] = (j * dp[i - 1][j] + dp[i - 1][j - 1]) if j > 0 else dp[i - 1][j - 1]

    return dp[n][m]

