from collections.abc import Iterator

class MergeIterator:
    def __init__(self, iterators):
        self.iterators = iterators
        self.heap = []
        for i, it in enumerate(iterators):
            try:
                first_item = next(it)
                heapq.heappush(self.heap, (first_item, i))
            except StopIteration:
                pass

    def __iter__(self):
        return self

    def __next__(self):
        if not self.heap:
            raise StopIteration

        item, index = heapq.heappop(self.heap)

        try:
            next_item = next(self.iterators[index])
            heapq.heappush(self.heap, (next_item, index))
        except StopIteration:
            self.iterators[index] = None
            # Clean up empty iterators from heap
            self.heap = [(val, idx) for val, idx in self.heap if self.iterators[idx] is not None]
            if not self.heap:
                raise StopIteration

        return item

