def get_divisors_sum(n):
    """Return the sum of proper divisors of n."""
    if n <= 1:
        return 0
    div_sum = 1
    i = 2
    while i * i <= n:
        if n % i == 0:
            div_sum += i
            if i != n // i:
                div_sum += n // i
        i += 1
    return div_sum

